// Bus Route Display � DE1-SoC  (AUTO-GENERATED by gen_rom.py)
// Phase 3: 3 buses, demo mode (SW[9]), road topology animation.
//
// SW[1:0]=scenario  SW[4:2]=time slot  SW[9]=demo mode
// Stop colours: Blue=Bus0/1-route  Green=Bus1-route  DimWhite=inactive
// Bus dots:     White=Bus0(ML)  Yellow=Bus1(ML)  Cyan=Bus2(all-stops)
// Demo mode:    SW[9]=1 cycles all 8 time slots per scenario then advances scenario

module bus_route (
    input  wire        CLOCK_50,
    input  wire [3:0]  KEY,
    input  wire [9:0]  SW,
    output wire [9:0]  LEDR,
    output wire [6:0]  HEX0, HEX1, HEX2, HEX3, HEX4, HEX5,
    output wire        GPIO_0_0
);

    localparam NUM_LEDS   = 156;
    localparam T0H=18, T0L=45, T1H=45, T1L=18, TRESET=3000;
    localparam MOVE_SPD   = 20;   // frames per LED step (~96ms)
    localparam DWELL_TIME = 400;  // frames at stop (~1.9s)
    assign HEX0=7'h7F; assign HEX1=7'h7F; assign HEX2=7'h7F;
    assign HEX3=7'h7F; assign HEX4=7'h7F; assign HEX5=7'h7F;

    reg [1:0] rst_sync;
    wire rst_n = rst_sync[1];
    always @(posedge CLOCK_50) rst_sync <= {rst_sync[0], KEY[0]};

    // Demo mode: SW[9]=1 cycles all 8 time slots for one scenario, then
    // advances to the next scenario, cycling all 4 scenarios before looping.
    // 1,500,000,000 / 50MHz = exactly 30 seconds per time slot.
    reg [30:0] demo_ctr;
    reg [2:0]  demo_ts;
    reg [1:0]  demo_sc;
    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) begin demo_ctr <= 31'd0; demo_ts <= 3'd0; demo_sc <= 2'd0; end
        else begin
            if (demo_ctr == 31'd1_499_999_999) begin
                demo_ctr <= 31'd0;
                if (demo_ts == 3'd7) begin
                    demo_ts <= 3'd0;
                    demo_sc <= demo_sc + 2'd1;  // wraps 3->0 naturally
                end else begin
                    demo_ts <= demo_ts + 3'd1;
                end
            end else begin
                demo_ctr <= demo_ctr + 31'd1;
            end
        end
    end
    wire [1:0] eff_sc   = SW[9] ? demo_sc : SW[1:0];
    wire [2:0] eff_ts   = SW[9] ? demo_ts : SW[4:2];
    wire [4:0] rom_addr = {eff_sc, eff_ts};

    reg  [4:0] sw_prev;
    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) sw_prev <= 5'h1F;
        else if (frame_done) sw_prev <= rom_addr;
    end
    wire sw_changed = (rom_addr != sw_prev);

