    function [3:0] demand_rom;
        input [4:0] addr;
        input [3:0] stop;
        reg [59:0] row;
        begin
            case (addr)
                5'd 0: row = 60'h645588655844888; // Sunny Early Morning
                5'd 1: row = 60'h757698767866988; // Sunny AM Peak
                5'd 2: row = 60'h786648756855888; // Sunny Mid Morning
                5'd 3: row = 60'h786548656855888; // Sunny Lunch
                5'd 4: row = 60'h787648767865888; // Sunny Afternoon
                5'd 5: row = 60'h747688767866888; // Sunny PM Peak
                5'd 6: row = 60'h787648767865888; // Sunny Evening
                5'd 7: row = 60'h645500655044800; // Sunny Night
                5'd 8: row = 60'h686548655854888; // Rain Early Morning
                5'd 9: row = 60'h797659767866989; // Rain AM Peak
                5'd10: row = 60'h747688766855888; // Rain Mid Morning
                5'd11: row = 60'h746588756855888; // Rain Lunch
                5'd12: row = 60'h747688767866888; // Rain Afternoon
                5'd13: row = 60'h747688767866888; // Rain PM Peak
                5'd14: row = 60'h787648767866888; // Rain Evening
                5'd15: row = 60'h646588656054808; // Rain Night
                5'd16: row = 60'h685540645844808; // Festival Early Morning
                5'd17: row = 60'h787588756855444; // Festival AM Peak
                5'd18: row = 60'h746588756855888; // Festival Mid Morning
                5'd19: row = 60'h747588656855800; // Festival Lunch
                5'd20: row = 60'h747688757855888; // Festival Afternoon
                5'd21: row = 60'h747688757855808; // Festival PM Peak
                5'd22: row = 60'h787648756055808; // Festival Evening
                5'd23: row = 60'h706540656054800; // Festival Night
                5'd24: row = 60'h645588555844888; // Storm Early Morning
                5'd25: row = 60'h797658767866988; // Storm AM Peak
                5'd26: row = 60'h686548656855888; // Storm Mid Morning
                5'd27: row = 60'h646588656855888; // Storm Lunch
                5'd28: row = 60'h747688766855888; // Storm Afternoon
                5'd29: row = 60'h787648766855888; // Storm PM Peak
                5'd30: row = 60'h746688766855888; // Storm Evening
                5'd31: row = 60'h545400544044400; // Storm Night
                default: row = 60'h0;
            endcase
            case (stop)
                4'd 0: demand_rom = row[59:56];
                4'd 1: demand_rom = row[55:52];
                4'd 2: demand_rom = row[51:48];
                4'd 3: demand_rom = row[47:44];
                4'd 4: demand_rom = row[43:40];
                4'd 5: demand_rom = row[39:36];
                4'd 6: demand_rom = row[35:32];
                4'd 7: demand_rom = row[31:28];
                4'd 8: demand_rom = row[27:24];
                4'd 9: demand_rom = row[23:20];
                4'd10: demand_rom = row[19:16];
                4'd11: demand_rom = row[15:12];
                4'd12: demand_rom = row[11:8];
                4'd13: demand_rom = row[7:4];
                4'd14: demand_rom = row[3:0];
                default: demand_rom = 4'h0;
            endcase
        end
    endfunction

    function [23:0] stop_color;
        input [3:0] rv;
        reg [7:0] bri;
        begin
            case (rv[1:0]) 2'd3: bri=8'hFF; 2'd2: bri=8'hB0; 2'd1: bri=8'h70; default: bri=8'h30; endcase
            case (rv[3:2]) 2'd1: stop_color={8'h00,8'h00,bri}; 2'd2: stop_color={bri,8'h00,8'h00}; default: stop_color=24'h050505; endcase
        end
    endfunction

    localparam WS_RESET=2'd0, WS_SENDBIT=2'd1, WS_DONE=2'd2;
    reg [1:0]  ws_state;
    reg [15:0] ws_tick;
    reg [7:0]  ws_led;
    reg [4:0]  ws_bit;
    reg        ws_phase, ws_out, frame_done;

    reg        b0_state;      // 0=DWELL 1=TRAVEL
    reg [3:0]  b0_stop_idx;
    reg [7:0]  b0_path_id;
    reg [7:0]  b0_path_step;
    reg [7:0]  b0_path_len;
    reg [9:0]  b0_dwell_tmr;
    reg [5:0]  b0_move_tmr;
    reg        b1_state;      // 0=DWELL 1=TRAVEL
    reg [3:0]  b1_stop_idx;
    reg [7:0]  b1_path_id;
    reg [7:0]  b1_path_step;
    reg [7:0]  b1_path_len;
    reg [9:0]  b1_dwell_tmr;
    reg [5:0]  b1_move_tmr;
    reg        b2_state;      // 0=DWELL 1=TRAVEL
    reg [3:0]  b2_stop_idx;
    reg [7:0]  b2_path_id;
    reg [7:0]  b2_path_step;
    reg [7:0]  b2_path_len;
    reg [9:0]  b2_dwell_tmr;
    reg [5:0]  b2_move_tmr;

    wire [3:0]  b0_rlen     = route_len(rom_addr, 1'b0);
    wire [3:0]  b0_nxt_idx  = (b0_stop_idx + 4'd1 >= b0_rlen) ? 4'd0 : b0_stop_idx + 4'd1;
    wire [7:0]  b0_cur_sled = route_stop_led(rom_addr, 1'b0, b0_stop_idx);
    wire [7:0]  b0_nxt_sled = route_stop_led(rom_addr, 1'b0, b0_nxt_idx);
    wire [7:0]  b0_jrn_pid  = get_path_id(b0_cur_sled, b0_nxt_sled);
    wire [7:0]  b0_jrn_len  = get_path_len(b0_jrn_pid);
    wire [7:0]  b0_disp_led = (b0_state == 1'b0) ? b0_cur_sled : path_rom(b0_path_id, b0_path_step);

    wire [3:0]  b1_rlen     = route_len(rom_addr, 1'b1);
    wire [3:0]  b1_nxt_idx  = (b1_stop_idx + 4'd1 >= b1_rlen) ? 4'd0 : b1_stop_idx + 4'd1;
    wire [7:0]  b1_cur_sled = route_stop_led(rom_addr, 1'b1, b1_stop_idx);
    wire [7:0]  b1_nxt_sled = route_stop_led(rom_addr, 1'b1, b1_nxt_idx);
    wire [7:0]  b1_jrn_pid  = get_path_id(b1_cur_sled, b1_nxt_sled);
    wire [7:0]  b1_jrn_len  = get_path_len(b1_jrn_pid);
    wire [7:0]  b1_disp_led = (b1_state == 1'b0) ? b1_cur_sled : path_rom(b1_path_id, b1_path_step);

    wire [3:0]  b2_nxt_idx  = (b2_stop_idx == 4'd14) ? 4'd0 : b2_stop_idx + 4'd1;
    wire [7:0]  b2_cur_sled = b2_stop_led(b2_stop_idx);
    wire [7:0]  b2_nxt_sled = b2_stop_led(b2_nxt_idx);
    wire [7:0]  b2_jrn_pid  = get_path_id(b2_cur_sled, b2_nxt_sled);
    wire [7:0]  b2_jrn_len  = get_path_len(b2_jrn_pid);
    wire [7:0]  b2_disp_led = (b2_state == 1'b0) ? b2_cur_sled : path_rom(b2_path_id, b2_path_step);

    reg [23:0] cur_color;
    always @(*) begin
        if      (ws_led == 8'd0)        cur_color = 24'h101010; // heartbeat LED0
        else if (ws_led == b0_disp_led) cur_color = 24'hFFFFFF; // bus0 white
        else if (ws_led == b1_disp_led) cur_color = 24'hFFFF00; // bus1 yellow
        else if (ws_led == b2_disp_led) cur_color = 24'h00FFFF; // bus2 cyan
        else if (ws_led == 8'd106) cur_color = stop_color(demand_rom(rom_addr, 4'd0));
        else if (ws_led == 8'd114) cur_color = stop_color(demand_rom(rom_addr, 4'd1));
        else if (ws_led == 8'd33) cur_color = stop_color(demand_rom(rom_addr, 4'd2));
        else if (ws_led == 8'd70) cur_color = stop_color(demand_rom(rom_addr, 4'd3));
        else if (ws_led == 8'd78) cur_color = stop_color(demand_rom(rom_addr, 4'd4));
        else if (ws_led == 8'd25) cur_color = stop_color(demand_rom(rom_addr, 4'd5));
        else if (ws_led == 8'd65) cur_color = stop_color(demand_rom(rom_addr, 4'd6));
        else if (ws_led == 8'd58) cur_color = stop_color(demand_rom(rom_addr, 4'd7));
        else if (ws_led == 8'd95) cur_color = stop_color(demand_rom(rom_addr, 4'd8));
        else if (ws_led == 8'd21) cur_color = stop_color(demand_rom(rom_addr, 4'd9));
        else if (ws_led == 8'd50) cur_color = stop_color(demand_rom(rom_addr, 4'd10));
        else if (ws_led == 8'd44) cur_color = stop_color(demand_rom(rom_addr, 4'd11));
        else if (ws_led == 8'd142) cur_color = stop_color(demand_rom(rom_addr, 4'd12));
        else if (ws_led == 8'd11) cur_color = stop_color(demand_rom(rom_addr, 4'd13));
        else if (ws_led == 8'd1) cur_color = stop_color(demand_rom(rom_addr, 4'd14));
        else                             cur_color = 24'h000000;
    end

    wire cur_bit = cur_color[23 - ws_bit];

    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) begin
            ws_state<=WS_RESET; ws_tick<=0; ws_led<=0; ws_bit<=0; ws_phase<=0; ws_out<=0; frame_done<=0;
        end else begin
            frame_done <= 0;
            case (ws_state)
                WS_RESET: begin
                    ws_out <= 0;
                    if (ws_tick==TRESET-1) begin ws_tick<=0; ws_led<=0; ws_bit<=0; ws_phase<=0; ws_state<=WS_SENDBIT; end
                    else ws_tick <= ws_tick + 1;
                end
                WS_SENDBIT: begin
                    if (!ws_phase) begin
                        ws_out <= 1;
                        if ((cur_bit&&ws_tick==T1H-1)||(!cur_bit&&ws_tick==T0H-1)) begin ws_tick<=0; ws_phase<=1; end
                        else ws_tick <= ws_tick + 1;
                    end else begin
                        ws_out <= 0;
                        if ((cur_bit&&ws_tick==T1L-1)||(!cur_bit&&ws_tick==T0L-1)) begin
                            ws_tick<=0; ws_phase<=0;
                            if (ws_bit==23) begin ws_bit<=0; if (ws_led==NUM_LEDS-1) ws_state<=WS_DONE; else ws_led<=ws_led+1; end
                            else ws_bit <= ws_bit + 1;
                        end else ws_tick <= ws_tick + 1;
                    end
                end
                WS_DONE: begin ws_out<=0; frame_done<=1; ws_state<=WS_RESET; ws_tick<=0; end
            endcase`
        end
    end
    assign GPIO_0_0 = ws_out;

    // ---- Bus 0 state machine (ML-driven) ----
    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) begin
            b0_state     <= 1'b0;
            b0_stop_idx  <= 4'd0;
            b0_path_id   <= 8'd0;
            b0_path_step <= 8'd0;
            b0_path_len  <= 8'd1;
            b0_dwell_tmr <= 10'd400;
            b0_move_tmr  <= 6'd20;
        end else if (frame_done) begin
            if (sw_changed) begin
                b0_state     <= 1'b0;
                b0_stop_idx  <= 4'd0;
                b0_path_id   <= 8'd0;
                b0_path_step <= 8'd0;
                b0_path_len  <= 8'd1;
                b0_dwell_tmr <= 10'd400;
                b0_move_tmr  <= 6'd20;
            end else if (b0_state == 1'b0) begin // DWELL
                if (b0_dwell_tmr == 10'd0) begin
                    if (b0_rlen > 4'd1 && b0_jrn_len > 8'd1) begin
                        b0_state     <= 1'b1;
                        b0_path_id   <= b0_jrn_pid;
                        b0_path_len  <= b0_jrn_len;
                        b0_path_step <= 8'd1;
                        b0_stop_idx  <= b0_nxt_idx;
                        b0_move_tmr  <= 6'd20;
                    end else begin
                        b0_dwell_tmr <= 10'd400;
                    end
                end else b0_dwell_tmr <= b0_dwell_tmr - 10'd1;
            end else begin // TRAVEL
                if (b0_move_tmr == 6'd0) begin
                    if (b0_path_step >= b0_path_len - 8'd1) begin
                        b0_state     <= 1'b0;
                        b0_dwell_tmr <= 10'd400;
                    end else begin
                        b0_path_step <= b0_path_step + 8'd1;
                        b0_move_tmr  <= 6'd20;
                    end
                end else b0_move_tmr <= b0_move_tmr - 6'd1;
            end
        end
    end

    // ---- Bus 1 state machine (ML-driven) ----
    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) begin
            b1_state     <= 1'b0;
            b1_stop_idx  <= 4'd0;
            b1_path_id   <= 8'd0;
            b1_path_step <= 8'd0;
            b1_path_len  <= 8'd1;
            b1_dwell_tmr <= 10'd400;
            b1_move_tmr  <= 6'd20;
        end else if (frame_done) begin
            if (sw_changed) begin
                b1_state     <= 1'b0;
                b1_stop_idx  <= 4'd0;
                b1_path_id   <= 8'd0;
                b1_path_step <= 8'd0;
                b1_path_len  <= 8'd1;
                b1_dwell_tmr <= 10'd400;
                b1_move_tmr  <= 6'd20;
            end else if (b1_state == 1'b0) begin // DWELL
                if (b1_dwell_tmr == 10'd0) begin
                    if (b1_rlen > 4'd1 && b1_jrn_len > 8'd1) begin
                        b1_state     <= 1'b1;
                        b1_path_id   <= b1_jrn_pid;
                        b1_path_len  <= b1_jrn_len;
                        b1_path_step <= 8'd1;
                        b1_stop_idx  <= b1_nxt_idx;
                        b1_move_tmr  <= 6'd20;
                    end else begin
                        b1_dwell_tmr <= 10'd400;
                    end
                end else b1_dwell_tmr <= b1_dwell_tmr - 10'd1;
            end else begin // TRAVEL
                if (b1_move_tmr == 6'd0) begin
                    if (b1_path_step >= b1_path_len - 8'd1) begin
                        b1_state     <= 1'b0;
                        b1_dwell_tmr <= 10'd400;
                    end else begin
                        b1_path_step <= b1_path_step + 8'd1;
                        b1_move_tmr  <= 6'd20;
                    end
                end else b1_move_tmr <= b1_move_tmr - 6'd1;
            end
        end
    end

    // ---- Bus 2 state machine (fixed all-stops circuit, cyan) ----
    // Bus 2 is independent of ML data - does NOT reset on sw_changed.
    // Starts at stop 7 (S08) to spread visually from buses 0 and 1.
    always @(posedge CLOCK_50 or negedge rst_n) begin
        if (!rst_n) begin
            b2_state     <= 1'b0;
            b2_stop_idx  <= 4'd7;   // S08 start (spread from buses 0+1)
            b2_path_id   <= 8'd0;
            b2_path_step <= 8'd0;
            b2_path_len  <= 8'd1;
            b2_dwell_tmr <= 10'd400;
            b2_move_tmr  <= 6'd20;
        end else if (frame_done) begin
            if (b2_state == 1'b0) begin // DWELL
                if (b2_dwell_tmr == 10'd0) begin
                    if (b2_jrn_len > 8'd1) begin
                        b2_state     <= 1'b1;
                        b2_path_id   <= b2_jrn_pid;
                        b2_path_len  <= b2_jrn_len;
                        b2_path_step <= 8'd1;
                        b2_stop_idx  <= b2_nxt_idx;
                        b2_move_tmr  <= 6'd20;
                    end else begin
                        b2_dwell_tmr <= 10'd400;
                    end
                end else b2_dwell_tmr <= b2_dwell_tmr - 10'd1;
            end else begin // TRAVEL
                if (b2_move_tmr == 6'd0) begin
                    if (b2_path_step >= b2_path_len - 8'd1) begin
                        b2_state     <= 1'b0;
                        b2_dwell_tmr <= 10'd400;
                    end else begin
                        b2_path_step <= b2_path_step + 8'd1;
                        b2_move_tmr  <= 6'd20;
                    end
                end else b2_move_tmr <= b2_move_tmr - 6'd1;
            end
        end
    end

    assign LEDR[1:0] = SW[1:0];      // current scenario
    assign LEDR[2]   = b0_state;     // 1=bus0 travelling
    assign LEDR[3]   = b1_state;     // 1=bus1 travelling
    assign LEDR[4]   = b2_state;     // 1=bus2 travelling
    assign LEDR[5]   = SW[9];        // 1=demo mode active
    assign LEDR[6]   = 1'b0;
    assign LEDR[7]   = ~b0_state;    // 1=bus0 at stop
    assign LEDR[8]   = ~b1_state;    // 1=bus1 at stop
    assign LEDR[9]   = rst_n;        // 1=system running

endmodule
